//
import { mathSQRT } from '../core/zc-constants';
import { isObjectPropDefined } from '../utils/zcutils';

export function segmentSelection(points, mouse, chart, key) {
    var doRadiusSearch = chart.cache.search.bisect,
        points_scatter = doRadiusSearch ? points : points,
        mindist,
        point;
    if (!points_scatter) {
        return;
    }
    mouse = [mouse.x, mouse.y];
    points_scatter.map(p => {
        mindist = chart.eventHandler.dataAccesor().radius(key);

        var renderer = chart.renderer[p.seriesIndex],
            // bbox = renderer.getSymbolBBox(p),
            // segments = segmentsForSymbol(p, chart, bbox),
            segments =
                p.type === 'zc-marker'
                    ? isObjectPropDefined(chart.cache, `parser.${[p.__key]}._highlighter`, true).getSegments(p)
                    : renderer.getSegments(p);
        if(segments){
            segments.map(s => {
                let dist = s ? distToSegment(mouse, s[0], s[1]) : mathSQRT(dist2(mouse, [p._x, p._y]));
                if (dist < mindist || mindist == null) {
                    mindist = dist;
                    point = p;
                }
            });
        }else{
            let dist = dist2(mouse, [p._x, p._y]);
            if (dist < mindist || mindist == null) {
                mindist = dist;
                point = p;
            }

        }

    });
    return point;
}

export function distToSegment(p, v, w) {
    return mathSQRT(distToSegmentSquared(p, v, w));
}
function distToSegmentSquared(p, v, w) {
    var l2 = dist2(v, w);
    if (l2 === 0) {
        return dist2(p, v);
    }
    var t = ((p[0] - v[0]) * (w[0] - v[0]) + (p[1] - v[1]) * (w[1] - v[1])) / l2;
    if (t < 0) {
        return dist2(p, v);
    }
    if (t > 1) {
        return dist2(p, w);
    }
    return dist2(p, [v[0] + t * (w[0] - v[0]), v[1] + t * (w[1] - v[1])]);
}
function sqr(x) {
    return x * x;
}

export function dist2(v, w) {
    return sqr(v[0] - w[0]) + sqr(v[1] - w[1]);
}
